     1→/**
     2→ * ScenarioComparisonView
     3→ *
     4→ * Side-by-side comparison view for what-if scenarios against baseline.
     5→ * Allows users to visually compare PM schedules between scenarios.
     6→ *
     7→ * Features:
     8→ * - Split view with baseline on left, scenario on right
     9→ * - Synchronized scrolling between views
    10→ * - Highlighted differences (added, removed, moved PMs)
    11→ * - Summary statistics comparison
    12→ *
    13→ * @see specs/006-user-interface.md Section 6.4.5
    14→ */
    15→
    16→import {
    17→  Button,
    18→  ButtonGroup,
    19→  Card,
    20→  HTMLSelect,
    21→  Icon,
    22→  Intent,
    23→  NonIdealState,
    24→  Tag,
    25→} from '@blueprintjs/core';
    26→
    27→import { useScenario } from '../../store';
    28→import type { ScenarioSliceState } from '../../store/slices/scenario';
    29→
    30→// =============================================================================
    31→// Constants
    32→// =============================================================================
    33→
    34→const LAYOUT = {
    35→  MIN_WIDTH: 800,
    36→  HEADER_HEIGHT: 56,
    37→  TOOLBAR_HEIGHT: 48,
    38→  SUMMARY_HEIGHT: 80,
    39→  CANVAS_HEIGHT: 400,
    40→} as const;
    41→
    42→const CHANGE_COLORS = {
    43→  ADDED: '#16A34A',
    44→  REMOVED: '#DC2626',
    45→  MOVED: '#2563EB',
    46→  UNCHANGED: '#64748B',
    47→};
    48→
    49→// =============================================================================
    50→// Types
    51→// =============================================================================
    52→
    53→interface ComparisonDelta {
    54→  pmId: string;
    55→  trainNumber: string;
    56→  pmCode: string;
    57→  changeType: 'ADDED' | 'REMOVED' | 'MOVED' | 'UNCHANGED';
    58→  baselineDate?: string;
    59→  scenarioDate?: string;
    60→  driftDays?: number;
    61→}
    62→
    63→interface ComparisonSummary {
    64→  totalChanges: number;
    65→  added: number;
    66→  removed: number;
    67→  moved: number;
    68→  unchanged: number;
    69→  totalCostImpact: number;
    70→  totalManhourImpact: number;
    71→}
    72→
    73→// =============================================================================
    74→// Helper Functions
    75→// =============================================================================
    76→
    77→function getChangeIcon(changeType: ComparisonDelta['changeType']): 'plus' | 'minus' | 'swap-horizontal' | 'tick' {
    78→  switch (changeType) {
    79→    case 'ADDED':
    80→      return 'plus';
    81→    case 'REMOVED':
    82→      return 'minus';
    83→    case 'MOVED':
    84→      return 'swap-horizontal';
    85→    case 'UNCHANGED':
    86→      return 'tick';
    87→    default:
    88→      return 'tick';
    89→  }
    90→}
    91→
    92→function getChangeIntent(changeType: ComparisonDelta['changeType']): typeof Intent[keyof typeof Intent] {
    93→  switch (changeType) {
    94→    case 'ADDED':
    95→      return Intent.SUCCESS;
    96→    case 'REMOVED':
    97→      return Intent.DANGER;
    98→    case 'MOVED':
    99→      return Intent.PRIMARY;
   100→    case 'UNCHANGED':
   101→      return Intent.NONE;
   102→    default:
   103→      return Intent.NONE;
   104→  }
   105→}
   106→
   107→function formatCostImpact(cost: number): string {
   108→  if (cost === 0) return '$0';
   109→  const sign = cost > 0 ? '+' : '';
   110→  if (Math.abs(cost) >= 1000000) {
   111→    return `${sign}$${(cost / 1000000).toFixed(1)}M`;
   112→  }
   113→  if (Math.abs(cost) >= 1000) {
   114→    return `${sign}$${(cost / 1000).toFixed(0)}K`;
   115→  }
   116→  return `${sign}$${cost.toFixed(0)}`;
   117→}
   118→
   119→// =============================================================================
   120→// Sub-Components
   121→// =============================================================================
   122→
   123→interface SummaryCardProps {
   124→  title: string;
   125→  value: string | number;
   126→  intent?: typeof Intent[keyof typeof Intent];
   127→  subtitle?: string;
   128→  icon?: 'changes' | 'dollar' | 'time';
   129→}
   130→
   131→function SummaryCard({ title, value, intent, subtitle, icon }: SummaryCardProps) {
   132→  const iconName = icon === 'changes' ? 'changes' : icon === 'dollar' ? 'dollar' : 'time';
   133→
   134→  return (
   135→    <div
   136→      style={{
   137→        flex: 1,
   138→        padding: '12px 16px',
   139→        backgroundColor: 'var(--pt-app-background-color)',
   140→        borderRadius: 4,
   141→        textAlign: 'center',
   142→      }}
   143→    >
   144→      <div style={{ fontSize: 10, color: 'var(--pt-text-muted)', marginBottom: 4 }}>
   145→        {icon && <Icon icon={iconName} size={10} style={{ marginRight: 4 }} />}
   146→        {title}
   147→      </div>
   148→      <div
   149→        style={{
   150→          fontSize: 20,
   151→          fontWeight: 700,
   152→          color: intent ? `var(--pt-intent-${intent === Intent.DANGER ? 'danger' : intent === Intent.SUCCESS ? 'success' : 'primary'})` : 'var(--pt-text-color)',
   153→        }}
   154→      >
   155→        {value}
   156→      </div>
   157→      {subtitle && (
   158→        <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
   159→          {subtitle}
   160→        </div>
   161→      )}
   162→    </div>
   163→  );
   164→}
   165→
   166→interface DeltaRowProps {
   167→  delta: ComparisonDelta;
   168→  onNavigate?: (pmId: string) => void;
   169→}
   170→
   171→function DeltaRow({ delta, onNavigate }: DeltaRowProps) {
   172→  const { pmId, trainNumber, pmCode, changeType, baselineDate, scenarioDate, driftDays } = delta;
   173→
   174→  return (
   175→    <div
   176→      style={{
   177→        display: 'flex',
   178→        alignItems: 'center',
   179→        gap: 8,
   180→        padding: '8px 12px',
   181→        borderLeft: `3px solid ${CHANGE_COLORS[changeType]}`,
   182→        backgroundColor: changeType !== 'UNCHANGED' ? 'var(--pt-intent-primary-5)' : 'transparent',
   183→        marginBottom: 2,
   184→        borderRadius: '0 4px 4px 0',
   185→      }}
   186→    >
   187→      <Icon
   188→        icon={getChangeIcon(changeType)}
   189→        intent={getChangeIntent(changeType)}
   190→        size={14}
   191→      />
   192→
   193→      <div style={{ flex: 1 }}>
   194→        <div style={{ fontSize: 12, fontWeight: 500 }}>
   195→          {trainNumber} - {pmCode}
   196→        </div>
   197→        <div style={{ fontSize: 10, color: 'var(--pt-text-muted)' }}>
   198→          {changeType === 'ADDED' && scenarioDate && `Added: ${scenarioDate}`}
   199→          {changeType === 'REMOVED' && baselineDate && `Removed: ${baselineDate}`}
   200→          {changeType === 'MOVED' && baselineDate && scenarioDate && (
   201→            <>
   202→              {baselineDate} → {scenarioDate}
   203→              {driftDays !== undefined && (
   204→                <span style={{ marginLeft: 4, color: driftDays > 0 ? CHANGE_COLORS.REMOVED : CHANGE_COLORS.ADDED }}>
   205→                  ({driftDays > 0 ? '+' : ''}{driftDays}d)
   206→                </span>
   207→              )}
   208→            </>
   209→          )}
   210→          {changeType === 'UNCHANGED' && baselineDate && `${baselineDate}`}
   211→        </div>
   212→      </div>
   213→
   214→      {changeType !== 'UNCHANGED' && (
   215→        <Tag intent={getChangeIntent(changeType)} minimal>
   216→          {changeType}
   217→        </Tag>
   218→      )}
   219→
   220→      {onNavigate && (
   221→        <Button
   222→          minimal
   223→          small
   224→          icon="locate"
   225→          onClick={() => onNavigate(pmId)}
   226→        />
   227→      )}
   228→    </div>
   229→  );
   230→}
   231→
   232→interface ComparisonCanvasPlaceholderProps {
   233→  title: string;
   234→  data: ComparisonDelta[];
   235→  emptyMessage: string;
   236→}
   237→
   238→function ComparisonCanvasPlaceholder({ title, data, emptyMessage }: ComparisonCanvasPlaceholderProps) {
   239→  const changes = data.filter(d => d.changeType !== 'UNCHANGED');
   240→
   241→  return (
   242→    <div
   243→      style={{
   244→        flex: 1,
   245→        display: 'flex',
   246→        flexDirection: 'column',
   247→        border: '1px solid var(--pt-divider-black)',
   248→        borderRadius: 4,
   249→        overflow: 'hidden',
   250→      }}
   251→    >
   252→      <div
   253→        style={{
   254→          padding: '8px 12px',
   255→          borderBottom: '1px solid var(--pt-divider-black)',
   256→          backgroundColor: 'var(--pt-divider-black)',
   257→          fontWeight: 600,
   258→          fontSize: 12,
   259→        }}
   260→      >
   261→        {title}
   262→      </div>
   263→
   264→      <div style={{ flex: 1, overflow: 'auto', padding: 8 }}>
   265→        {data.length === 0 ? (
   266→          <div style={{ textAlign: 'center', padding: 24, color: 'var(--pt-text-muted)' }}>
   267→            {emptyMessage}
   268→          </div>
   269→        ) : (
   270→          data.map(delta => (
   271→            <DeltaRow key={delta.pmId} delta={delta} />
   272→          ))
   273→        )}
   274→      </div>
   275→
   276→      <div
   277→        style={{
   278→          padding: '8px 12px',
   279→          borderTop: '1px solid var(--pt-divider-black)',
   280→          backgroundColor: 'var(--pt-divider-black)',
   281→          fontSize: 10,
   282→          display: 'flex',
   283→          gap: 12,
   284→        }}
   285→      >
   286→        <span>{data.length} total PMs</span>
   287→        <span style={{ color: changes.length > 0 ? CHANGE_COLORS.MOVED : 'var(--pt-text-muted)' }}>
   288→          {changes.length} changes
   289→        </span>
   290→      </div>
   291→    </div>
   292→  );
   293→}
   294→
   295→// =============================================================================
   296→// Main Component
   297→// =============================================================================
   298→
   299→export interface ScenarioComparisonViewProps {
   300→  onClose?: () => void;
   301→  onPromote?: (scenarioId: string) => void;
   302→  onDiscard?: (scenarioId: string) => void;
   303→}
   304→
   305→export function ScenarioComparisonView({ onClose, onPromote, onDiscard }: ScenarioComparisonViewProps) {
   306→  const { state: scenarioStateRaw, actions: scenarioActions } = useScenario();
   307→
   308→  const scenarioState = scenarioStateRaw as unknown as ScenarioSliceState;
   309→
   310→  const {
   311→    scenarios,
   312→    baselines,
   313→    activeScenarioId,
   314→    isComparing,
   315→    activeDeltas,
   316→    comparisonBaselineId,
   317→  } = scenarioState;
   318→
   319→  const activeScenario = scenarios.find(s => s.id === activeScenarioId);
   320→  const activeBaseline = baselines.find(b => b.status === 'PUBLISHED');
   321→  const comparisonBaseline = comparisonBaselineId
   322→    ? baselines.find(b => b.id === comparisonBaselineId)
   323→    : activeBaseline;
   324→
   325→  // Build comparison deltas from active scenario deltas
   326→  const mockDeltas: ComparisonDelta[] = activeDeltas.map((d) => ({
   327→    pmId: d.entityId,
   328→    trainNumber: `TR-${d.entityId.slice(-4)}`,
   329→    pmCode: (d.newValues as Record<string, unknown>)?.pmCode as string ?? 'C1',
   330→    changeType: d.deltaType === 'PM_ADD' ? 'ADDED' as const :
   331→                d.deltaType === 'PM_REMOVE' ? 'REMOVED' as const :
   332→                d.deltaType === 'PM_MOVE' ? 'MOVED' as const : 'UNCHANGED' as const,
   333→    baselineDate: d.oldValues ? String((d.oldValues as Record<string, unknown>).targetDate ?? '') : undefined,
   334→    scenarioDate: d.newValues ? String((d.newValues as Record<string, unknown>).targetDate ?? '') : undefined,
   335→    driftDays: d.oldValues && d.newValues ?
   336→      Math.floor((new Date(String((d.newValues as Record<string, unknown>).targetDate ?? '')).getTime() -
   337→                  new Date(String((d.oldValues as Record<string, unknown>).targetDate ?? '')).getTime()) / (1000 * 60 * 60 * 24)) : undefined,
   338→  }));
   339→
   340→  const summary: ComparisonSummary = {
   341→    totalChanges: mockDeltas.filter(d => d.changeType !== 'UNCHANGED').length,
   342→    added: mockDeltas.filter(d => d.changeType === 'ADDED').length,
   343→    removed: mockDeltas.filter(d => d.changeType === 'REMOVED').length,
   344→    moved: mockDeltas.filter(d => d.changeType === 'MOVED').length,
   345→    unchanged: mockDeltas.filter(d => d.changeType === 'UNCHANGED').length,
   346→    totalCostImpact: 0, // Would be calculated from deltas in production
   347→    totalManhourImpact: 0, // Would be calculated from deltas in production
   348→  };
   349→
   350→  const handleScenarioChange = (event: React.ChangeEvent<HTMLSelectElement>) => {
   351→    const scenarioId = event.target.value;
   352→    if (scenarioId) {
   353→      scenarioActions.setActiveScenario(scenarioId);
   354→    }
   355→  };
   356→
   357→  const handleCompare = () => {
   358→    if (activeScenarioId && activeBaseline) {
   359→      scenarioActions.startComparison({ baselineId: activeBaseline.id });
   360→    }
   361→  };
   362→
   363→  const handlePromote = () => {
   364→    if (activeScenarioId && onPromote) {
   365→      onPromote(activeScenarioId);
   366→    }
   367→  };
   368→
   369→  const handleDiscard = () => {
   370→    if (activeScenarioId && onDiscard) {
   371→      onDiscard(activeScenarioId);
   372→    }
   373→  };
   374→
   375→  // No active scenario
   376→  if (!activeScenario && scenarios.length === 0) {
   377→    return (
   378→      <Card elevation={2} data-testid="scenario-comparison" style={{ margin: 16, padding: 24 }}>
   379→        <NonIdealState
   380→          icon="comparison"
   381→          title="No Scenarios"
   382→          description="Create a scenario to compare against the baseline"
   383→          action={
   384→            <Button intent={Intent.PRIMARY} icon="add">
   385→              Create Scenario
   386→            </Button>
   387→          }
   388→        />
   389→        {onClose && (
   390→          <div style={{ position: 'absolute', top: 8, right: 8 }}>
   391→            <Button minimal icon="cross" onClick={onClose} />
   392→          </div>
   393→        )}
   394→      </Card>
   395→    );
   396→  }
   397→
   398→  return (
   399→    <div
   400→      data-testid="scenario-comparison"
   401→      style={{
   402→        position: 'absolute',
   403→        top: 0,
   404→        left: 0,
   405→        right: 0,
   406→        bottom: 0,
   407→        backgroundColor: 'var(--pt-app-background-color)',
   408→        zIndex: 30,
   409→        display: 'flex',
   410→        flexDirection: 'column',
   411→      }}
   412→    >
   413→      {/* Header */}
   414→      <div
   415→        style={{
   416→          height: LAYOUT.HEADER_HEIGHT,
   417→          display: 'flex',
   418→          alignItems: 'center',
   419→          gap: 16,
   420→          padding: '0 16px',
   421→          borderBottom: '1px solid var(--pt-divider-black)',
   422→          backgroundColor: 'white',
   423→        }}
   424→      >
   425→        <Icon icon="comparison" size={20} intent={Intent.PRIMARY} />
   426→        <div style={{ flex: 1 }}>
   427→          <div style={{ fontSize: 16, fontWeight: 600 }}>Scenario Comparison</div>
   428→          <div style={{ fontSize: 11, color: 'var(--pt-text-muted)' }}>
   429→            Compare what-if scenarios against published baseline
   430→          </div>
   431→        </div>
   432→
   433→        <ButtonGroup>
   434→          {activeScenario && (
   435→            <>
   436→              <Button
   437→                intent={Intent.SUCCESS}
   438→                icon="tick"
   439→                onClick={handlePromote}
   440→              >
   441→                Promote
   442→              </Button>
   443→              <Button
   444→                intent={Intent.DANGER}
   445→                icon="trash"
   446→                onClick={handleDiscard}
   447→              >
   448→                Discard
   449→              </Button>
   450→            </>
   451→          )}
   452→          {onClose && (
   453→            <Button minimal icon="cross" onClick={onClose} />
   454→          )}
   455→        </ButtonGroup>
   456→      </div>
   457→
   458→      {/* Toolbar */}
   459→      <div
   460→        style={{
   461→          height: LAYOUT.TOOLBAR_HEIGHT,
   462→          display: 'flex',
   463→          alignItems: 'center',
   464→          gap: 12,
   465→          padding: '0 16px',
   466→          borderBottom: '1px solid var(--pt-divider-black)',
   467→        }}
   468→      >
   469→        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   470→          <span style={{ fontSize: 12, color: 'var(--pt-text-muted)' }}>Scenario:</span>
   471→          <HTMLSelect
   472→            value={activeScenarioId || ''}
   473→            onChange={handleScenarioChange}
   474→            minimal
   475→            style={{ minWidth: 200 }}
   476→          >
   477→            <option value="">Select scenario...</option>
   478→            {scenarios.filter(s => s.status === 'ACTIVE').map(scenario => (
   479→              <option key={scenario.id} value={scenario.id}>
   480→                {scenario.name} ({scenario.changeCount} changes)
   481→              </option>
   482→            ))}
   483→          </HTMLSelect>
   484→        </div>
   485→
   486→        <Icon icon="arrow-right" size={12} color="var(--pt-text-muted)" />
   487→
   488→        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
   489→          <span style={{ fontSize: 12, color: 'var(--pt-text-muted)' }}>Baseline:</span>
   490→          <Tag minimal intent={Intent.PRIMARY}>
   491→            {comparisonBaseline?.name ?? 'No baseline'}
   492→          </Tag>
   493→        </div>
   494→
   495→        <div style={{ flex: 1 }} />
   496→
   497→        <Button
   498→          intent={Intent.PRIMARY}
   499→          icon="comparison"
   500→          onClick={handleCompare}
   501→          disabled={!activeScenarioId || !activeBaseline}
   502→        >
   503→          Compare
   504→        </Button>
   505→      </div>
   506→
   507→      {/* Summary */}
   508→      {isComparing && (
   509→        <div
   510→          style={{
   511→            display: 'flex',
   512→            gap: 12,
   513→            padding: 16,
   514→            borderBottom: '1px solid var(--pt-divider-black)',
   515→          }}
   516→        >
   517→          <SummaryCard
   518→            title="TOTAL CHANGES"
   519→            value={summary.totalChanges}
   520→            intent={summary.totalChanges > 0 ? Intent.PRIMARY : Intent.NONE}
   521→            icon="changes"
   522→          />
   523→          <SummaryCard
   524→            title="ADDED"
   525→            value={summary.added}
   526→            intent={summary.added > 0 ? Intent.SUCCESS : Intent.NONE}
   527→          />
   528→          <SummaryCard
   529→            title="REMOVED"
   530→            value={summary.removed}
   531→            intent={summary.removed > 0 ? Intent.DANGER : Intent.NONE}
   532→          />
   533→          <SummaryCard
   534→            title="MOVED"
   535→            value={summary.moved}
   536→            intent={summary.moved > 0 ? Intent.PRIMARY : Intent.NONE}
   537→          />
   538→          <SummaryCard
   539→            title="COST IMPACT"
   540→            value={formatCostImpact(summary.totalCostImpact)}
   541→            intent={summary.totalCostImpact > 0 ? Intent.DANGER : summary.totalCostImpact < 0 ? Intent.SUCCESS : Intent.NONE}
   542→            icon="dollar"
   543→          />
   544→        </div>
   545→      )}
   546→
   547→      {/* Comparison content */}
   548→      <div style={{ flex: 1, display: 'flex', gap: 16, padding: 16, overflow: 'hidden' }}>
   549→        {!isComparing && !activeScenarioId && (
   550→          <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
   551→            <NonIdealState
   552→              icon="comparison"
   553→              title="Select and Compare"
   554→              description="Select a scenario and click Compare to see differences"
   555→            />
   556→          </div>
   557→        )}
   558→
   559→        {isComparing && (
   560→          <>
   561→            <ComparisonCanvasPlaceholder
   562→              title={`Baseline: ${comparisonBaseline?.name ?? 'Published'}`}
   563→              data={mockDeltas.filter(d => d.baselineDate)}
   564→              emptyMessage="No baseline PMs in selected period"
   565→            />
   566→            <ComparisonCanvasPlaceholder
   567→              title={`Scenario: ${activeScenario?.name ?? 'Active'}`}
   568→              data={mockDeltas.filter(d => d.scenarioDate || d.changeType === 'ADDED')}
   569→              emptyMessage="No scenario changes"
   570→            />
   571→          </>
   572→        )}
   573→      </div>
   574→    </div>
   575→  );
   576→}
   577→

