/**
 * Scenario Slice
 *
 * State management for what-if scenarios and comparison views.
 * Supports event-sourced delta tracking per spec 004.11.
 *
 * @see specs/006-user-interface.md Section 6.7
 */

import { createSlice, createAsyncSlice } from '@belt/tools';
import type {
  Scenario,
  ScenarioDelta,
  ScenarioStatus,
  DeltaType,
  Baseline,
  DriftAnalysis,
} from '../types';

// =============================================================================
// Scenario Slice State
// =============================================================================

export interface ScenarioSliceState {
  scenarios: Scenario[];
  activeScenarioId: string | null;
  activeDeltas: ScenarioDelta[];
  isComparing: boolean;
  comparisonScenarioId: string | null;
  comparisonBaselineId: string | null;
  baselines: Baseline[];
  activeBaselineId: string | null;
  driftAnalysis: DriftAnalysis[];
  isCreating: boolean;
  createError: string | null;
  isPromoting: boolean;
  promotionError: string | null;
  [key: string]: unknown;
}

const initialScenarioState: ScenarioSliceState = {
  scenarios: [],
  activeScenarioId: null,
  activeDeltas: [],
  isComparing: false,
  comparisonScenarioId: null,
  comparisonBaselineId: null,
  baselines: [],
  activeBaselineId: null,
  driftAnalysis: [],
  isCreating: false,
  createError: null,
  isPromoting: false,
  promotionError: null,
};

export const scenarioSlice = createSlice({
  id: 'scenario',
  initial: initialScenarioState,
  cache: { policy: 'session' },
  reducers: {
    // Scenarios
    setScenarios: (s, scenarios: Scenario[]) => {
      const state = s as ScenarioSliceState;
      state.scenarios = scenarios;
    },

    addScenario: (s, scenario: Scenario) => {
      const state = s as ScenarioSliceState;
      state.scenarios.push(scenario);
    },

    updateScenario: (s, scenario: Partial<Scenario> & { id: string }) => {
      const state = s as ScenarioSliceState;
      const index = state.scenarios.findIndex((sc) => sc.id === scenario.id);
      if (index !== -1) {
        state.scenarios[index] = { ...state.scenarios[index], ...scenario };
      }
    },

    removeScenario: (s, scenarioId: string) => {
      const state = s as ScenarioSliceState;
      state.scenarios = state.scenarios.filter((sc) => sc.id !== scenarioId);
      if (state.activeScenarioId === scenarioId) {
        state.activeScenarioId = null;
        state.activeDeltas = [];
      }
      if (state.comparisonScenarioId === scenarioId) {
        state.comparisonScenarioId = null;
        state.isComparing = false;
      }
    },

    updateScenarioStatus: (s, payload: { scenarioId: string; status: ScenarioStatus }) => {
      const state = s as ScenarioSliceState;
      const scenario = state.scenarios.find((sc) => sc.id === payload.scenarioId);
      if (scenario) {
        scenario.status = payload.status;
      }
    },

    // Active Scenario
    setActiveScenario: (s, scenarioId: string | null) => {
      const state = s as ScenarioSliceState;
      state.activeScenarioId = scenarioId;
      if (!scenarioId) {
        state.activeDeltas = [];
      }
    },

    setActiveDeltas: (s, deltas: ScenarioDelta[]) => {
      const state = s as ScenarioSliceState;
      state.activeDeltas = deltas;
    },

    addDelta: (s, delta: ScenarioDelta) => {
      const state = s as ScenarioSliceState;
      state.activeDeltas.push(delta);
      const scenario = state.scenarios.find((sc) => sc.id === state.activeScenarioId);
      if (scenario) {
        scenario.changeCount = state.activeDeltas.length;
        scenario.updatedAt = new Date().toISOString();
      }
    },

    undoLastDelta: (s) => {
      const state = s as ScenarioSliceState;
      if (state.activeDeltas.length > 0) {
        state.activeDeltas.pop();
        const scenario = state.scenarios.find((sc) => sc.id === state.activeScenarioId);
        if (scenario) {
          scenario.changeCount = state.activeDeltas.length;
          scenario.updatedAt = new Date().toISOString();
        }
      }
    },

    clearDeltas: (s) => {
      const state = s as ScenarioSliceState;
      state.activeDeltas = [];
    },

    // Comparison
    startComparison: (s, payload: { scenarioId?: string; baselineId?: string }) => {
      const state = s as ScenarioSliceState;
      state.isComparing = true;
      state.comparisonScenarioId = payload.scenarioId ?? null;
      state.comparisonBaselineId = payload.baselineId ?? null;
    },

    endComparison: (s) => {
      const state = s as ScenarioSliceState;
      state.isComparing = false;
      state.comparisonScenarioId = null;
      state.comparisonBaselineId = null;
    },

    setComparisonTarget: (s, payload: { type: 'scenario' | 'baseline'; id: string }) => {
      const state = s as ScenarioSliceState;
      if (payload.type === 'scenario') {
        state.comparisonScenarioId = payload.id;
        state.comparisonBaselineId = null;
      } else {
        state.comparisonBaselineId = payload.id;
        state.comparisonScenarioId = null;
      }
    },

    // Baselines
    setBaselines: (s, baselines: Baseline[]) => {
      const state = s as ScenarioSliceState;
      state.baselines = baselines;
    },

    addBaseline: (s, baseline: Baseline) => {
      const state = s as ScenarioSliceState;
      state.baselines.push(baseline);
    },

    updateBaseline: (s, baseline: Partial<Baseline> & { id: string }) => {
      const state = s as ScenarioSliceState;
      const index = state.baselines.findIndex((b) => b.id === baseline.id);
      if (index !== -1) {
        state.baselines[index] = { ...state.baselines[index], ...baseline };
      }
    },

    setActiveBaseline: (s, baselineId: string | null) => {
      const state = s as ScenarioSliceState;
      state.activeBaselineId = baselineId;
    },

    // Drift Analysis
    setDriftAnalysis: (s, analysis: DriftAnalysis[]) => {
      const state = s as ScenarioSliceState;
      state.driftAnalysis = analysis;
    },

    clearDriftAnalysis: (s) => {
      const state = s as ScenarioSliceState;
      state.driftAnalysis = [];
    },

    // Creation State
    startCreating: (s) => {
      const state = s as ScenarioSliceState;
      state.isCreating = true;
      state.createError = null;
    },

    finishCreating: (s, error?: string) => {
      const state = s as ScenarioSliceState;
      state.isCreating = false;
      state.createError = error ?? null;
    },

    // Promotion State
    startPromoting: (s) => {
      const state = s as ScenarioSliceState;
      state.isPromoting = true;
      state.promotionError = null;
    },

    finishPromoting: (s, error?: string) => {
      const state = s as ScenarioSliceState;
      state.isPromoting = false;
      state.promotionError = error ?? null;
    },

    // Reset
    reset: (s) => {
      const state = s as ScenarioSliceState;
      Object.assign(state, initialScenarioState);
    },

    resetComparison: (s) => {
      const state = s as ScenarioSliceState;
      state.isComparing = false;
      state.comparisonScenarioId = null;
      state.comparisonBaselineId = null;
    },
  },
});

// =============================================================================
// Async Scenario Slice
// =============================================================================

export interface ScenarioApiResponse {
  scenarios: Scenario[];
  baselines: Baseline[];
}

export const scenarioAsyncSlice = createAsyncSlice({
  id: 'scenarioApi',
  cache: {
    policy: 'private',
    ttl: '5m',
    swr: true,
  },
  context: { baseUrl: '/api/v1' },
  load: async (ctx) => {
    const baseUrl = (ctx as { baseUrl: string }).baseUrl;

    const [scenariosRes, baselinesRes] = await Promise.all([
      fetch(`${baseUrl}/scenarios?status=ACTIVE`),
      fetch(`${baseUrl}/baselines`),
    ]);

    if (!scenariosRes.ok || !baselinesRes.ok) {
      throw new Error('Failed to fetch scenario data');
    }

    const [scenariosData, baselinesData] = await Promise.all([
      scenariosRes.json() as Promise<{ data: Scenario[] }>,
      baselinesRes.json() as Promise<{ data: Baseline[] }>,
    ]);

    return {
      scenarios: scenariosData.data,
      baselines: baselinesData.data,
    };
  },
});

// =============================================================================
// Selectors
// =============================================================================

export function selectScenarioById(
  state: ScenarioSliceState,
  scenarioId: string
): Scenario | undefined {
  return state.scenarios.find((s) => s.id === scenarioId);
}

export function selectActiveScenario(state: ScenarioSliceState): Scenario | undefined {
  return state.activeScenarioId
    ? state.scenarios.find((s) => s.id === state.activeScenarioId)
    : undefined;
}

export function selectBaselineById(
  state: ScenarioSliceState,
  baselineId: string
): Baseline | undefined {
  return state.baselines.find((b) => b.id === baselineId);
}

export function selectPublishedBaseline(state: ScenarioSliceState): Baseline | undefined {
  return state.baselines.find((b) => b.status === 'PUBLISHED');
}

export function selectActiveScenarios(state: ScenarioSliceState): Scenario[] {
  return state.scenarios.filter((s) => s.status === 'ACTIVE');
}

export function selectComparisonTarget(
  state: ScenarioSliceState
): { type: 'scenario' | 'baseline'; entity: Scenario | Baseline } | null {
  if (state.comparisonScenarioId) {
    const scenario = state.scenarios.find((s) => s.id === state.comparisonScenarioId);
    if (scenario) {
      return { type: 'scenario', entity: scenario };
    }
  }
  if (state.comparisonBaselineId) {
    const baseline = state.baselines.find((b) => b.id === state.comparisonBaselineId);
    if (baseline) {
      return { type: 'baseline', entity: baseline };
    }
  }
  return null;
}

export function selectTrainsRequiringReplan(state: ScenarioSliceState): DriftAnalysis[] {
  return state.driftAnalysis.filter((d) => d.requiresReplan);
}

export function selectDriftSummary(state: ScenarioSliceState): {
  totalTrains: number;
  lowDrift: number;
  mediumDrift: number;
  highDrift: number;
  criticalDrift: number;
  requireReplan: number;
} {
  const analysis = state.driftAnalysis;
  return {
    totalTrains: analysis.length,
    lowDrift: analysis.filter((d) => d.severity === 'LOW').length,
    mediumDrift: analysis.filter((d) => d.severity === 'MEDIUM').length,
    highDrift: analysis.filter((d) => d.severity === 'HIGH').length,
    criticalDrift: analysis.filter((d) => d.severity === 'CRITICAL').length,
    requireReplan: analysis.filter((d) => d.requiresReplan).length,
  };
}

export function selectDeltaCountByType(state: ScenarioSliceState): Record<DeltaType, number> {
  const counts: Record<DeltaType, number> = {
    PM_MOVE: 0,
    PM_ADD: 0,
    PM_REMOVE: 0,
    CAPACITY_CHANGE: 0,
    TRAIN_STATUS_CHANGE: 0,
  };

  state.activeDeltas.forEach((delta) => {
    counts[delta.deltaType]++;
  });

  return counts;
}

export function hasUnsavedChanges(state: ScenarioSliceState): boolean {
  return state.activeDeltas.length > 0;
}

/**
 * MMS Scenario Management Tables
 *
 * Event-sourced what-if analysis for PM schedule planning.
 *
 * Scenarios allow planners to:
 * - Fork from a baseline or another scenario
 * - Make changes (PM_MOVE, PM_ADD, PM_REMOVE, etc.)
 * - Compare scenarios side-by-side
 * - Promote winning scenario to new baseline
 *
 * Event sourcing: Changes are stored as deltas, not mutations.
 * This allows replaying history and comparing states.
 *
 * @see specs/003-database-schema.md Section 3.9
 */

import { relations, sql } from 'drizzle-orm';
import {
  date,
  decimal,
  index,
  integer,
  jsonb,
  pgTable,
  text,
  timestamp,
  uniqueIndex,
  uuid,
  varchar,
} from 'drizzle-orm/pg-core';
import { scenarioStatusEnum } from './enums';
import { planBaselines } from './baseline-drift';
import { users } from './users';

/**
 * Scenarios - What-if analysis containers
 *
 * Each scenario forks from a baseline or another scenario.
 * Changes are tracked as deltas for full history replay.
 *
 * Auto-expiration: Inactive scenarios expire after 30 days.
 */
export const scenarios = pgTable(
  'scenarios',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    name: varchar('name', { length: 100 }).notNull(),
    description: text('description'),

    // Fork point
    forkedFromBaselineId: uuid('forked_from_baseline_id').references(() => planBaselines.id),
    forkedFromScenarioId: uuid('forked_from_scenario_id'),
    forkedAt: timestamp('forked_at', { withTimezone: true }).defaultNow(),

    // Metadata
    status: scenarioStatusEnum('status').default('ACTIVE'),
    createdBy: uuid('created_by')
      .notNull()
      .references(() => users.id),
    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),

    // Expiration (auto-expire after 30 days of inactivity)
    lastModifiedAt: timestamp('last_modified_at', { withTimezone: true }).defaultNow(),
    expiresAt: timestamp('expires_at', { withTimezone: true }).default(
      sql`NOW() + INTERVAL '30 days'`
    ),

    // Promotion
    promotedToBaselineId: uuid('promoted_to_baseline_id').references(() => planBaselines.id),
    promotedAt: timestamp('promoted_at', { withTimezone: true }),
    promotedBy: uuid('promoted_by').references(() => users.id),
  },
  (table) => [
    index('idx_scenarios_status').on(table.status),
    index('idx_scenarios_user').on(table.createdBy, table.status),
    index('idx_scenarios_expiring').on(table.expiresAt),
  ]
);

/**
 * Scenario Deltas - Event-sourced changes
 *
 * Each delta represents a change made to the scenario.
 * Changes are applied in sequence_num order.
 *
 * Delta types:
 * - PM_MOVE: Reschedule PM to new date
 * - PM_ADD: Insert new PM
 * - PM_REMOVE: Delete PM
 * - CAPACITY_CHANGE: Modify man-hour capacity
 * - TRAIN_STATUS_CHANGE: Update train fitness/restrictions
 */
export const scenarioDeltas = pgTable(
  'scenario_deltas',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    scenarioId: uuid('scenario_id')
      .notNull()
      .references(() => scenarios.id, { onDelete: 'cascade' }),
    sequenceNum: integer('sequence_num').notNull(),

    deltaType: varchar('delta_type', { length: 50 }).notNull(),
    // 'PM_MOVE', 'PM_ADD', 'PM_REMOVE', 'CAPACITY_CHANGE', 'TRAIN_STATUS_CHANGE'

    // Reference to affected entity
    entityType: varchar('entity_type', { length: 50 }).notNull(), // 'pm_schedule', 'manhour_capacity', etc.
    entityId: uuid('entity_id').notNull(),

    // Change details
    oldValues: jsonb('old_values'),
    newValues: jsonb('new_values'),

    // Explanation
    changeReason: text('change_reason'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
    createdBy: uuid('created_by').references(() => users.id),
  },
  (table) => [
    uniqueIndex('idx_scenario_deltas_unique').on(table.scenarioId, table.sequenceNum),
    index('idx_scenario_deltas_scenario').on(table.scenarioId, table.sequenceNum),
  ]
);

/**
 * Scenario Comparisons - Pre-computed comparison results
 *
 * Materialized comparison between two scenarios or a scenario and baseline.
 * Created on-demand when user requests comparison.
 */
export const scenarioComparisons = pgTable(
  'scenario_comparisons',
  {
    id: uuid('id').primaryKey().defaultRandom(),
    scenarioAId: uuid('scenario_a_id')
      .notNull()
      .references(() => scenarios.id),
    scenarioBId: uuid('scenario_b_id').references(() => scenarios.id), // NULL = compare to baseline
    baselineId: uuid('baseline_id').references(() => planBaselines.id),

    comparisonDate: date('comparison_date').notNull(),

    // Summary metrics
    pmCountDelta: integer('pm_count_delta'),
    totalHoursDelta: decimal('total_hours_delta', { precision: 10, scale: 2 }),
    totalCostDelta: decimal('total_cost_delta', { precision: 12, scale: 2 }),
    overloadedWeeksDelta: integer('overloaded_weeks_delta'),

    // Detailed differences (JSON)
    pmDifferences: jsonb('pm_differences'),
    manhourDifferences: jsonb('manhour_differences'),

    createdAt: timestamp('created_at', { withTimezone: true }).defaultNow(),
  },
  (table) => [
    index('idx_scenario_comp_a').on(table.scenarioAId),
    index('idx_scenario_comp_b').on(table.scenarioBId),
  ]
);

// ============================================================================
// Relations
// ============================================================================

export const scenariosRelations = relations(scenarios, ({ one, many }) => ({
  forkedFromBaseline: one(planBaselines, {
    fields: [scenarios.forkedFromBaselineId],
    references: [planBaselines.id],
    relationName: 'forkedFromBaseline',
  }),
  forkedFromScenario: one(scenarios, {
    fields: [scenarios.forkedFromScenarioId],
    references: [scenarios.id],
    relationName: 'forkedFrom',
  }),
  createdByUser: one(users, {
    fields: [scenarios.createdBy],
    references: [users.id],
    relationName: 'createdBy',
  }),
  promotedToBaseline: one(planBaselines, {
    fields: [scenarios.promotedToBaselineId],
    references: [planBaselines.id],
    relationName: 'promotedTo',
  }),
  promotedByUser: one(users, {
    fields: [scenarios.promotedBy],
    references: [users.id],
    relationName: 'promotedBy',
  }),
  deltas: many(scenarioDeltas),
}));

export const scenarioDeltasRelations = relations(scenarioDeltas, ({ one }) => ({
  scenario: one(scenarios, {
    fields: [scenarioDeltas.scenarioId],
    references: [scenarios.id],
  }),
  createdByUser: one(users, {
    fields: [scenarioDeltas.createdBy],
    references: [users.id],
  }),
}));

export const scenarioComparisonsRelations = relations(scenarioComparisons, ({ one }) => ({
  scenarioA: one(scenarios, {
    fields: [scenarioComparisons.scenarioAId],
    references: [scenarios.id],
    relationName: 'scenarioA',
  }),
  scenarioB: one(scenarios, {
    fields: [scenarioComparisons.scenarioBId],
    references: [scenarios.id],
    relationName: 'scenarioB',
  }),
  baseline: one(planBaselines, {
    fields: [scenarioComparisons.baselineId],
    references: [planBaselines.id],
  }),
}));

