export type FitnessStatus = 'FIT' | 'RESTRICTED' | 'GROUNDED';
export type PmStatus = 'SCHEDULED' | 'IN_PROGRESS' | 'COMPLETED' | 'CANCELLED' | 'DEFERRED';
export type TrackType = 'LIGHT' | 'HEAVY' | 'OVERHAUL' | 'STABLING';
export type DayType = 'WEEKDAY' | 'SATURDAY' | 'SUNDAY' | 'HOLIDAY';

/** Train entity optimized for UI rendering */
export interface Train {
  id: string;
  trainNumber: string;
  fleetId: string;
  fleetCode: string;
  currentMileageKm: number;
  targetMileageKm: number | null;
  fitnessStatus: FitnessStatus;
  fitnessNotes: string | null;
  currentDepotId: string | null;
  homeDepotId: string | null;
  displayColor: string;
  commissioningDate: string | null;
  updatedAt: string;
}

/** Fleet entity */
export interface Fleet {
  id: string;
  code: string;
  name: string;
  manufacturer: string | null;
  carsPerTrain: number;
  baseDepotId: string | null;
  displayColor: string;
}

/** Depot entity */
export interface Depot {
  id: string;
  code: string;
  name: string;
  timezone: string;
  latitude: number | null;
  longitude: number | null;
}

/** Route entity */
export interface Route {
  id: string;
  routeCode: string;
  name: string;
  expectedKmPerDay: number;
  requiredTrains: number;
  allowedFleetIds: string[];
}

// =============================================================================
// PM Schedule Types
// =============================================================================

/** PM type definition */
export interface PmType {
  id: string;
  fleetId: string;
  pmCode: string;
  description: string | null;
  intervalKm: number | null;
  intervalMonths: number | null;
  satisfiesCodes: string[];
  estimatedHours: number;
  trackType: TrackType;
}

/** PM schedule entry for canvas rendering */
export interface PmScheduleEntry {
  id: string;
  trainId: string;
  trainNumber: string;
  pmTypeId: string;
  pmCode: string;
  targetDate: string;
  status: PmStatus;
  constraintStart: string | null;
  constraintEnd: string | null;
  assignedTrackId: string | null;
  isLocked: boolean;
  lockedBy: string | null;
  lockedAt: string | null;
  scenarioId: string | null;
  estimatedHours: number;
  displayColor: string;
}

/** Drag-drop preview state */
export interface DragState {
  isDragging: boolean;
  pmId: string | null;
  sourceDate: string | null;
  targetDate: string | null;
  isValid: boolean;
  validationMessage: string | null;
  constraintViolations: ConstraintViolation[];
}

/** Constraint violation for drag preview */
export interface ConstraintViolation {
  type: 'COMPLIANCE_WINDOW' | 'TRACK_CONFLICT' | 'MATERIAL' | 'MAXIMO_LOCK' | 'SERVICE_DEMAND';
  severity: 'ERROR' | 'WARNING';
  message: string;
}

// =============================================================================
// Canvas Types
// =============================================================================

export type ZoomLevel = 'STRATEGIC' | 'TACTICAL_WIDE' | 'TACTICAL' | 'OPERATIONAL' | 'DETAIL';

/** Canvas viewport state */
export interface ViewportBounds {
  startDate: string;
  endDate: string;
  trainIds: string[];
}

/** Canvas layer visibility */
export interface LayerVisibility {
  pmBlocks: boolean;
  complianceWindows: boolean;
  manhourOverlay: boolean;
  driftOverlay: boolean;
  baselineShadow: boolean;
}

/** Canvas selection state */
export interface CanvasSelection {
  selectedPmIds: string[];
  selectedTrainIds: string[];
  isMultiSelect: boolean;
}

